    def test_base(self, g, e_edges):
        var_name = get_var_name(g)
        r = weighted_user_graph(g)
        r_edges = r.edges(data='weight')
        self.assertTrue(len(r_edges)>0 or g == s_5_5)
        self.assertTrue(all((u,v,w) in e_edges or (v,u,w) in r_edges for u,v,w in r_edges), f"Grafo {var_name}")
        self.assertTrue(all((u,v,w) in r_edges or (v,u,w) in e_edges for u,v,w in r_edges), f"Grafo {var_name}")
   
    def test_None(self):
        self.assertIsNone(weighted_user_graph(None))

    def test_null(self):
        self.assertIsNone(weighted_user_graph(nx.MultiGraph()))

    def test_graph_structure(self):
        #Testa se o resultado é um Grafo Simples com propriedade 'weight' nas arestas.
        result = weighted_user_graph(Sauget_3_2)
        self.assertIsInstance(result, nx.Graph)
        edge_data = [data for u, v, data in result.edges(data=True)]
        self.assertTrue(all('weight' in data for data in edge_data), f"Alguma aresta sem propriedade 'weight'")
        self.assertTrue(all(data['weight'] is not None for data in edge_data), f"Alguma aresta tem valor None em 'weight'")


